/*
 * honua.io Public Safety Ops demo — Maui, Hawaiʻi. SIMULATED SCENARIO.
 *
 * A county-style emergency-operations board. All incident traffic, response
 * units, and advisory zones are synthetic, generated by generate-scenario.mjs
 * and replayed on a deterministic 10-minute loop (elapsed-time based — no
 * wall-clock seeding). Real Maui geography and the hazard layers from the
 * shared contract (assets/demo/layers.json) provide the backdrop.
 *
 * Two lanes feed the SAME @honua/sdk-js realtime store:
 *   - replay lane (default, server-independent): a local transport that
 *     replays assets/demos/public-safety/scenario.json
 *   - live lane (config-gated probe): the server's SSE feature stream at
 *     /api/v1/streaming/features (Pro). Graceful chip when absent.
 *
 * SDK surface used (see assets/demos/public-safety/README.md for the bundles):
 *   window.HonuaSDK     (shared vendored bundle, assets/vendor/)
 *     - new HonuaSDK.HonuaClient({ baseUrl })
 *     - client.getLayerMetadata(serviceId, layerId)         (hazard probes)
 *     - HonuaSDK.createDataset(...) + source.queryAll()     (hazard polygons)
 *     - HonuaSDK.isHonuaError / HonuaHttpError / HonuaNetworkError
 *   window.HonuaSDKOps  (page-scoped bundle, this directory)
 *     - HonuaSDKOps.createRealtimeFeatureStore()
 *     - HonuaSDKOps.createRealtimeServerSentEventsTransport({ url, ... })
 *     - new HonuaSDKOps.HonuaGeocodingClient({ baseUrl, locatorName })
 */
(function () {
  "use strict";

  var LAYERS_URL = "assets/demo/layers.json";
  var CONFIG_URL = "assets/demos/public-safety/config.json";

  function el(id) {
    return document.getElementById(id);
  }

  function escapeHtml(value) {
    return String(value)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#39;");
  }

  function pad2(n) {
    return (n < 10 ? "0" : "") + n;
  }

  function fmtClock(seconds) {
    var s = Math.max(0, Math.floor(seconds));
    return "T+" + pad2(Math.floor(s / 60)) + ":" + pad2(s % 60);
  }

  function setStatus(state, text) {
    var pill = el("ps-status");
    if (!pill) return;
    pill.dataset.state = state;
    pill.textContent = text;
  }

  function setChip(id, state, text) {
    var chip = el(id);
    if (!chip) return;
    chip.dataset.state = state;
    chip.textContent = text;
  }

  /* ── geometry: Esri JSON → GeoJSON + point-in-polygon ───────────────
   * Conversion helpers mirror assets/demo/demo.js (the SDK returns
   * GeoServices geometries and does not ship a GeoJSON converter). */

  function esriRingArea(ring) {
    var area = 0;
    for (var i = 0; i < ring.length - 1; i++) {
      area += (ring[i + 1][0] - ring[i][0]) * (ring[i + 1][1] + ring[i][1]);
    }
    return area; /* > 0 = clockwise (shell), < 0 = counter-clockwise (hole) */
  }

  function pointInRing(pt, ring) {
    var inside = false;
    for (var i = 0, j = ring.length - 1; i < ring.length; j = i++) {
      var xi = ring[i][0];
      var yi = ring[i][1];
      var xj = ring[j][0];
      var yj = ring[j][1];
      var crosses = yi > pt[1] !== yj > pt[1] && pt[0] < ((xj - xi) * (pt[1] - yi)) / (yj - yi) + xi;
      if (crosses) inside = !inside;
    }
    return inside;
  }

  /* Even-odd test across every ring of one polygon (shells + holes). */
  function pointInRings(pt, rings) {
    var inside = false;
    for (var i = 0; i < rings.length; i++) {
      if (pointInRing(pt, rings[i])) inside = !inside;
    }
    return inside;
  }

  function esriRingsToGeoJson(rings) {
    var shells = [];
    var holes = [];
    for (var i = 0; i < rings.length; i++) {
      var ring = rings[i];
      if (!Array.isArray(ring) || ring.length < 4) continue;
      (esriRingArea(ring) > 0 ? shells : holes).push(ring);
    }
    if (shells.length === 0) {
      return rings.length ? { type: "Polygon", coordinates: rings } : null;
    }
    var polygons = shells.map(function (shell) {
      return [shell];
    });
    for (var h = 0; h < holes.length; h++) {
      var host = null;
      for (var p = 0; p < polygons.length; p++) {
        if (pointInRing(holes[h][0], polygons[p][0])) {
          host = polygons[p];
          break;
        }
      }
      (host || polygons[0]).push(holes[h]);
    }
    return polygons.length === 1
      ? { type: "Polygon", coordinates: polygons[0] }
      : { type: "MultiPolygon", coordinates: polygons };
  }

  function polygonFeaturesToGeoJson(features) {
    var out = [];
    for (var i = 0; i < features.length; i++) {
      var geom = features[i].geometry;
      if (!geom || !Array.isArray(geom.rings)) continue;
      var converted = esriRingsToGeoJson(geom.rings);
      if (!converted) continue;
      out.push({ type: "Feature", geometry: converted, properties: features[i].attributes || {} });
    }
    return { type: "FeatureCollection", features: out };
  }

  function isNotFound(error) {
    var S = window.HonuaSDK;
    return (
      S.isHonuaError(error) &&
      error instanceof S.HonuaHttpError &&
      (error.statusCode === 404 || error.statusCode === 400 || error.statusCode === 402)
    );
  }

  /* ── shared app state ───────────────────────────────────────────── */

  var app = {
    map: null,
    layersConfig: null, // shared contract assets/demo/layers.json
    config: null, // page config
    scenario: null,
    places: null,
    store: null, // SDK realtime feature store (both lanes)
    lane: "replay",
    liveAvailable: false,
    geocoder: null, // live HonuaGeocodingClient or null
    geocodeLane: "fixture",
    startMs: 0,
    loopCount: 1,
    alertsFired: {}, // reset every loop
    floodSource: "zones", // "fema" | "zones"
    floodPolygons: [], // array of ring-arrays for PIP
    unitsAvailable: 0,
    incidentMarkers: {},
    unitMarkers: {},
    searchMarker: null,
    selectedId: null,
    hazardStates: [],
  };

  function elapsedSeconds() {
    var duration = app.scenario.meta.durationSeconds;
    var raw = (performance.now() - app.startMs) / 1000;
    return raw % duration;
  }

  /* ── code strip ─────────────────────────────────────────────────── */

  var SNIPPETS = null;

  function buildSnippets(base, cfg, layersCfg) {
    var streamUrl = base + cfg.live.streamPath;
    return {
      realtime: {
        label: "realtime — SSE incident stream",
        badge: "PRO",
        code: [
          '// live incident lane — SSE feature stream (Pro)',
          "var transport = HonuaSDKOps.createRealtimeServerSentEventsTransport({",
          '  url: "' + streamUrl + '",',
          '  eventTypes: ["status", "heartbeat", "feature-change"],',
          "  eventSourceFactory: function (url, init) { return new EventSource(url, init); },",
          "  encodeRequest: function (url, req) {     // server expects serviceId= & layers=",
          '    url.searchParams.set("serviceId", String(req.sourceId));',
          '    url.searchParams.set("layers", String(req.layerId));',
          "  },",
          "  decodeEvent: toRealtimeEvent             // feature-change -> upsert / delete",
          "});",
          "",
          "var store = HonuaSDKOps.createRealtimeFeatureStore();",
          "store.subscribe(function (state) { renderBoard(state.records); });",
          'store.connect(transport, { sourceId: "' + cfg.live.serviceId + '", layerId: ' + cfg.live.layerId + ' });',
          "",
          "// replay lane (this page's default): the SAME store, fed by a scripted",
          "// transport replaying scenario.json on a deterministic 10-minute loop.",
        ].join("\n"),
      },
      hazard: {
        label: "hazard layers — contract query",
        badge: "COMMUNITY",
        code: (function () {
          var floodDef = null;
          if (layersCfg && Array.isArray(layersCfg.layers)) {
            for (var li = 0; li < layersCfg.layers.length; li++) {
              if (layersCfg.layers[li].id === "flood-hazard") { floodDef = layersCfg.layers[li]; break; }
            }
          }
          var floodLayerId = floodDef ? floodDef.service.layerId : 4;
          var floodServiceId = floodDef ? floodDef.service.serviceId : "maui-flood-hazard";
          return [
          "// hazard context — FEMA flood zones via the protocol-neutral contract",
          'var client = new HonuaSDK.HonuaClient({ baseUrl: "' + base + '" });',
          "var dataset = HonuaSDK.createDataset({",
          '  id: "maui-hazards", client: client,',
          "  sources: [{",
          '    id: "flood-hazard",',
          '    protocol: "geoservices-feature-service",',
          '    locator: { url: "' + base + '", serviceId: "' + floodServiceId + '", layerId: ' + floodLayerId + ' },',
          '    capabilities: HonuaSDK.PROTOCOL_DEFAULT_CAPABILITIES["geoservices-feature-service"]',
          "  }]",
          "});",
          'var result = await dataset.source("flood-hazard").queryAll({',
          '  where: "1=1", returnGeometry: true, outSr: 4326, pagination: { limit: 4000 }',
          "});",
          '// the "in flood zone" KPI is a client-side point-in-polygon of every',
          "// active incident against result.features.",
          ].join("\n");
        })(),
      },
      geocode: {
        label: "geocoding — dispatch search",
        badge: "PRO",
        code: [
          "// dispatch search — forward geocoding (Pro)",
          "var geocoder = new HonuaSDKOps.HonuaGeocodingClient({",
          '  baseUrl: "' + base + '", locatorName: "' + cfg.geocoding.locatorName + '",',
          "  fetchFn: window.fetch.bind(window)",
          "});",
          'var candidates = await geocoder.forwardGeocode("Maui Memorial Medical Center", {',
          "  maxResults: " + cfg.geocoding.maxResults + ', spatialReferenceWkid: 4326, countryCodes: "' + cfg.geocoding.countryCodes + '"',
          "});",
          "map.flyTo({ center: [candidates[0].longitude, candidates[0].latitude], zoom: 14 });",
          "",
          "// replay-lane fallback: the bundled GNIS place-name fixture (places.json)",
          "// keeps the interaction working before the locator is licensed/seeded.",
        ].join("\n"),
      },
      edit: {
        label: "editing — acknowledge incident",
        badge: "PRO",
        code: [
          "// acknowledge an incident — one applyEdits call against the same source",
          "// (open-protocol editing = Community; Esri FeatureServer applyEdits = Pro)",
          'await dataset.source("incidents").applyEdits({',
          "  updates: [{",
          '    id: "INC-1004",',
          '    attributes: { status: "acknowledged", acknowledged_by: "eoc-operator" }',
          "  }],",
          "  rollbackOnFailure: true",
          "});",
          "",
          "// replay lane: the edit is applied to the local realtime store only.",
        ].join("\n"),
      },
      alert: {
        label: "alerts — geofence + threshold rules",
        badge: "PRO / ENTERPRISE",
        code: [
          "// server-side alert rules (admin API), evaluated against the same stream.",
          "// geofence enter/exit triggers + webhook delivery = Pro",
          "POST /api/v1/admin/alerts/rules",
          '{ "serviceId": "' + cfg.live.serviceId + '", "layerId": ' + cfg.live.layerId + ', "zoneId": 12,',
          '  "ruleName": "Incident inside flood advisory zone",',
          '  "triggerType": "enter", "severity": "critical",',
          '  "editionRequired": "pro", "channels": ["webhook"] }',
          "",
          "// dwell + attribute-threshold triggers, email/Slack/Teams channels = Enterprise",
          "POST /api/v1/admin/alerts/rules",
          '{ "serviceId": "' + cfg.live.serviceId + '", "layerId": ' + cfg.live.layerId + ",",
          '  "ruleName": "Active incidents at or above 6",',
          '  "triggerType": "threshold",',
          '  "conditionsJson": "{\\"field\\":\\"active_incidents\\",\\"operator\\":\\">=\\",\\"value\\":6}",',
          '  "editionRequired": "enterprise", "channels": ["email", "slack"] }',
          "",
          "// this page simulates both rules client-side in the replay lane.",
        ].join("\n"),
      },
    };
  }

  function setSnippet(key) {
    var snip = SNIPPETS && SNIPPETS[key];
    if (!snip) return;
    el("ps-code-label").textContent = snip.label;
    var badge = el("ps-code-badge");
    badge.hidden = false;
    badge.textContent = snip.badge;
    badge.className = "psops-badge " + (snip.badge.indexOf("ENTERPRISE") !== -1 ? "enterprise" : snip.badge === "COMMUNITY" ? "community" : "pro");
    el("ps-code").textContent = snip.code;
    var list = el("ps-capability-list");
    if (list) {
      var rows = list.querySelectorAll("li");
      for (var i = 0; i < rows.length; i++) {
        rows[i].dataset.active = String(rows[i].dataset.snippet === key);
      }
    }
  }

  function wireCodeStrip() {
    var strip = el("ps-codestrip");
    var toggle = el("ps-code-toggle");
    toggle.addEventListener("click", function () {
      var open = strip.dataset.open === "true";
      strip.dataset.open = String(!open);
      toggle.setAttribute("aria-expanded", String(!open));
      toggle.textContent = open ? "▸ code" : "▾ code";
    });
    el("ps-code-copy").addEventListener("click", function () {
      var text = el("ps-code").textContent;
      var done = function () {
        el("ps-code-copy").textContent = "copied";
        window.setTimeout(function () {
          el("ps-code-copy").textContent = "copy";
        }, 1400);
      };
      if (navigator.clipboard && navigator.clipboard.writeText) {
        navigator.clipboard.writeText(text).then(done, function () {});
      } else {
        var ta = document.createElement("textarea");
        ta.value = text;
        document.body.appendChild(ta);
        ta.select();
        try {
          document.execCommand("copy");
        } catch (_e) {
          /* clipboard is cosmetic */
        }
        document.body.removeChild(ta);
        done();
      }
    });
    var list = el("ps-capability-list");
    list.addEventListener("click", function (event) {
      var row = event.target.closest ? event.target.closest("li[data-snippet]") : null;
      if (row) setSnippet(row.dataset.snippet);
    });
    list.addEventListener("keydown", function (event) {
      if (event.key !== "Enter" && event.key !== " ") return;
      var row = event.target.closest ? event.target.closest("li[data-snippet]") : null;
      if (row) {
        event.preventDefault();
        setSnippet(row.dataset.snippet);
      }
    });
  }

  /* ── toasts ─────────────────────────────────────────────────────── */

  function showToast(opts) {
    var host = el("ps-toasts");
    if (!host) return;
    while (host.children.length >= 3) host.removeChild(host.firstChild);
    var card = document.createElement("article");
    card.className = "psops-toast" + (opts.tone ? " psops-toast-" + opts.tone : "");
    card.innerHTML =
      '<p class="psops-toast-kicker mono">' +
      escapeHtml(opts.kicker) +
      ' <i class="psops-badge ' +
      escapeHtml(opts.badgeClass) +
      '">' +
      escapeHtml(opts.badge) +
      "</i></p>" +
      "<strong>" +
      escapeHtml(opts.title) +
      "</strong>" +
      "<p>" +
      escapeHtml(opts.body) +
      "</p>";
    host.appendChild(card);
    window.setTimeout(function () {
      if (card.parentNode === host) host.removeChild(card);
    }, 9000);
  }

  /* ── replay transport (drives the SDK realtime store locally) ───── */

  function createReplayTransport(scenario, hooks) {
    return {
      capabilities: {
        kind: "replay",
        resumeModes: [],
        emitsHeartbeats: true,
        emitsWatermarks: false,
      },
      subscribe: function (request, observer) {
        var closed = false;
        var index = 0;
        var lastElapsed = -1;
        var timer = null;

        function emitEvent(ev) {
          if (ev.op === "upsert") {
            observer.next({
              type: "upsert",
              feature: {
                id: ev.id,
                feature: ev.incident,
                version: ev.version,
                updatedAt: fmtClock(ev.t),
              },
            });
          } else {
            observer.next({ type: "delete", id: ev.id, version: ev.version });
          }
        }

        function tick() {
          if (closed) return;
          var elapsed = hooks.elapsed();
          if (elapsed < lastElapsed) {
            index = 0;
            observer.next({ type: "snapshot", features: [], replace: true });
            if (hooks.onLoop) hooks.onLoop();
          }
          lastElapsed = elapsed;
          while (index < scenario.events.length && scenario.events[index].t <= elapsed) {
            emitEvent(scenario.events[index]);
            index += 1;
          }
        }

        observer.next({ type: "snapshot", features: [], replace: true });
        observer.next({ type: "status", status: "live", receivedAt: 0 });
        tick();
        timer = window.setInterval(tick, 500);

        return {
          close: function () {
            if (closed) return;
            closed = true;
            window.clearInterval(timer);
            observer.complete();
          },
        };
      },
    };
  }

  /* ── live lane: SSE transport against the server's streaming API ── */

  function normalizeLiveIncident(payload) {
    var attrs = payload.attributes || {};
    var location = null;
    if (payload.geometry && payload.geometry.type === "Point" && Array.isArray(payload.geometry.coordinates)) {
      location = payload.geometry.coordinates;
    }
    return {
      id: String(payload.featureId !== undefined ? payload.featureId : payload.objectId),
      type: attrs.type || "incident",
      severity: attrs.severity || "moderate",
      title: attrs.title || attrs.name || "Incident " + String(payload.featureId || payload.objectId || ""),
      area: attrs.area || "",
      status: attrs.status || payload.operation,
      units: [],
      location: location,
    };
  }

  function decodeLiveFeatureEvent(payload) {
    if (payload && payload.type === "feature-change") {
      var id = payload.featureId !== undefined ? payload.featureId : payload.objectId;
      var cursor = payload.cursor !== undefined && payload.cursor !== null ? String(payload.cursor) : undefined;
      if (payload.operation === "delete") {
        return { type: "delete", id: id, eventId: payload.eventId, cursor: cursor, updatedAt: payload.timestamp };
      }
      return {
        type: "upsert",
        eventId: payload.eventId,
        cursor: cursor,
        feature: { id: id, feature: normalizeLiveIncident(payload), updatedAt: payload.timestamp },
      };
    }
    return window.HonuaSDKOps.decodeRealtimeServerSentEvent(payload);
  }

  function createLiveTransport(base, cfg) {
    return window.HonuaSDKOps.createRealtimeServerSentEventsTransport({
      url: base + cfg.live.streamPath,
      eventTypes: ["status", "heartbeat", "feature-change"],
      // SDK gap (filed): the default factory invokes EventSource without
      // `new`, which throws in browsers — provide an explicit factory.
      eventSourceFactory: function (url, init) {
        return new window.EventSource(url, init);
      },
      encodeRequest: function (url, request) {
        // @honua/sdk-js encodes sourceId=/layerId= by default; honua-server's
        // streaming endpoint expects serviceId= and layers=. Re-map here.
        url.searchParams.delete("sourceId");
        url.searchParams.delete("layerId");
        url.searchParams.delete("mode");
        url.searchParams.set("serviceId", String(request.sourceId));
        url.searchParams.set("layers", String(request.layerId));
      },
      decodeEvent: decodeLiveFeatureEvent,
    });
  }

  function probeLiveLane(base, cfg) {
    if (!cfg.live.enabled) {
      setChip("ps-live-chip", "absent", "live feed: disabled");
      return;
    }
    fetch(base + cfg.live.capabilitiesPath, { headers: { Accept: "application/json" } })
      .then(function (res) {
        if (res.status === 403) {
          setChip("ps-live-chip", "absent", "live feed: requires Pro — not enabled");
          return null;
        }
        if (!res.ok) {
          setChip("ps-live-chip", "absent", "live feed: not yet enabled");
          return null;
        }
        return res.json().then(
          function () {
            app.liveAvailable = true;
            setChip("ps-live-chip", "ok", "live feed: available");
            el("ps-live-connect").hidden = false;
          },
          function () {
            setChip("ps-live-chip", "absent", "live feed: not yet enabled");
          }
        );
      })
      .catch(function () {
        setChip("ps-live-chip", "absent", "live feed: not yet enabled");
      });
  }

  function connectLiveLane(base, cfg) {
    if (!app.liveAvailable || app.lane === "live") return;
    app.lane = "live";
    // Clear replay records before the live stream takes over the store.
    app.store.apply({ type: "snapshot", features: [], replace: true });
    app.store.connect(createLiveTransport(base, cfg), {
      sourceId: cfg.live.serviceId,
      layerId: cfg.live.layerId,
      mode: "snapshot-then-delta",
      requestId: "demo-public-safety",
    });
    setChip("ps-lane-chip", "live", "lane: live");
    setChip("ps-live-chip", "ok", "live feed: connected");
    el("ps-live-connect").hidden = true;
    setSnippet("realtime");
  }

  /* ── incident rendering: feed, markers, detail, KPIs ────────────── */

  function recordList() {
    var records = app.store.state.records;
    var out = [];
    var keys = Object.keys(records);
    for (var i = 0; i < keys.length; i++) out.push(records[keys[i]]);
    out.sort(function (a, b) {
      var ta = a.updatedAt || "";
      var tb = b.updatedAt || "";
      if (ta !== tb) return ta < tb ? 1 : -1;
      return String(a.id) < String(b.id) ? 1 : -1;
    });
    return out;
  }

  function incidentInFlood(incident) {
    if (!incident.location) return false;
    for (var i = 0; i < app.floodPolygons.length; i++) {
      if (pointInRings(incident.location, app.floodPolygons[i])) return true;
    }
    return false;
  }

  function renderKpis(records) {
    el("kpi-active").textContent = String(records.length);
    el("kpi-units").textContent = String(app.unitsAvailable);
    var inFlood = 0;
    for (var i = 0; i < records.length; i++) {
      if (incidentInFlood(records[i].feature)) inFlood += 1;
    }
    el("kpi-flood").textContent = String(inFlood);
    var label = el("kpi-flood-label");
    label.textContent = "in flood zone";
    label.title =
      app.floodSource === "fema"
        ? "Point-in-polygon against FEMA flood hazard zones (live layer)"
        : "Point-in-polygon against the simulated advisory zones (FEMA layer not yet seeded)";
  }

  function renderFeed(records) {
    var feed = el("ps-feed");
    feed.innerHTML = "";
    if (records.length === 0) {
      var empty = document.createElement("li");
      empty.className = "psops-feed-empty mono";
      empty.textContent = app.lane === "live" ? "no live incidents yet" : "scenario starting…";
      feed.appendChild(empty);
      return;
    }
    for (var i = 0; i < records.length; i++) {
      var rec = records[i];
      var inc = rec.feature;
      var row = document.createElement("li");
      row.className = "psops-feed-row";
      row.dataset.severity = inc.severity;
      row.dataset.selected = String(rec.id === app.selectedId);
      row.dataset.id = String(rec.id);
      row.innerHTML =
        '<span class="psops-feed-time mono">' +
        escapeHtml(rec.updatedAt || "") +
        "</span>" +
        '<span class="psops-feed-sev mono">' +
        escapeHtml(inc.severity) +
        "</span>" +
        '<span class="psops-feed-title">' +
        escapeHtml(inc.title) +
        "</span>" +
        '<span class="psops-feed-meta mono">' +
        escapeHtml(inc.area + " · " + inc.status + (inc.units && inc.units.length ? " · " + inc.units.join(", ") : "")) +
        (inc.acknowledged ? " · ✓ ack" : "") +
        "</span>";
      feed.appendChild(row);
    }
  }

  function syncIncidentMarkers(records) {
    var seen = {};
    for (var i = 0; i < records.length; i++) {
      var rec = records[i];
      var inc = rec.feature;
      if (!inc.location) continue;
      var id = String(rec.id);
      seen[id] = true;
      var entry = app.incidentMarkers[id];
      if (!entry) {
        var node = document.createElement("button");
        node.type = "button";
        node.className = "psops-incident";
        node.setAttribute("aria-label", "Incident " + id);
        (function (incidentId) {
          node.addEventListener("click", function (event) {
            event.stopPropagation();
            selectIncident(incidentId);
          });
        })(id);
        var marker = new window.maplibregl.Marker({ element: node }).setLngLat(inc.location).addTo(app.map);
        entry = { marker: marker, el: node };
        app.incidentMarkers[id] = entry;
      }
      entry.marker.setLngLat(inc.location);
      entry.el.dataset.severity = inc.severity;
      entry.el.dataset.selected = String(id === app.selectedId);
      entry.el.title = inc.title + " — " + inc.status + " (SIMULATED)";
    }
    var ids = Object.keys(app.incidentMarkers);
    for (var k = 0; k < ids.length; k++) {
      if (!seen[ids[k]]) {
        app.incidentMarkers[ids[k]].marker.remove();
        delete app.incidentMarkers[ids[k]];
      }
    }
  }

  function selectIncident(id) {
    app.selectedId = id;
    renderBoard(undefined);
    var rec = findRecord(id);
    if (rec && rec.feature.location) {
      app.map.flyTo({ center: rec.feature.location, zoom: Math.max(app.map.getZoom(), 11.5), duration: 700 });
    }
  }

  function findRecord(id) {
    var records = app.store.state.records;
    var keys = Object.keys(records);
    for (var i = 0; i < keys.length; i++) {
      if (String(records[keys[i]].id) === String(id)) return records[keys[i]];
    }
    return null;
  }

  function renderDetail() {
    var card = el("ps-detail");
    if (!app.selectedId) {
      card.hidden = true;
      card.innerHTML = "";
      return;
    }
    var rec = findRecord(app.selectedId);
    if (!rec) {
      // Incident cleared from the board (delete event) — close the card.
      app.selectedId = null;
      card.hidden = true;
      card.innerHTML = "";
      return;
    }
    var inc = rec.feature;
    card.hidden = false;
    card.innerHTML =
      '<p class="psops-detail-kicker mono">' +
      escapeHtml(String(rec.id) + " · " + inc.type + " · " + inc.severity) +
      ' <span class="psops-sim-tag">simulated</span></p>' +
      "<h3>" +
      escapeHtml(inc.title) +
      "</h3>" +
      '<div class="psops-detail-grid mono">' +
      detailRow("area", inc.area) +
      detailRow("status", inc.status + (inc.acknowledged ? " · ✓ acknowledged" : "")) +
      detailRow("units", inc.units && inc.units.length ? inc.units.join(", ") : "—") +
      detailRow("updated", rec.updatedAt || "—") +
      detailRow(
        "position",
        inc.location ? inc.location[1].toFixed(4) + ", " + inc.location[0].toFixed(4) : "—"
      ) +
      detailRow("in flood zone", incidentInFlood(inc) ? "yes" : "no") +
      "</div>" +
      '<div class="psops-detail-actions">' +
      (inc.acknowledged
        ? ""
        : '<button id="ps-detail-ack" class="psops-btn mono" type="button">acknowledge</button>') +
      '<button id="ps-detail-close" class="psops-btn mono" type="button">close</button>' +
      "</div>" +
      '<p class="psops-note mono">acknowledge = one source.applyEdits() call on a live server; the replay lane applies it to the local store.</p>';
    var ack = el("ps-detail-ack");
    if (ack) {
      ack.addEventListener("click", function () {
        acknowledgeIncident(String(rec.id));
      });
    }
    el("ps-detail-close").addEventListener("click", function () {
      app.selectedId = null;
      renderBoard(undefined);
    });
  }

  function detailRow(key, value) {
    return (
      '<span class="psops-detail-key">' +
      escapeHtml(key) +
      "</span><span>" +
      escapeHtml(value === undefined || value === null || value === "" ? "—" : value) +
      "</span>"
    );
  }

  function acknowledgeIncident(id) {
    var rec = findRecord(id);
    if (!rec) return;
    var next = {};
    var attrs = rec.feature;
    var keys = Object.keys(attrs);
    for (var i = 0; i < keys.length; i++) next[keys[i]] = attrs[keys[i]];
    next.acknowledged = true;
    next.acknowledged_by = "eoc-operator";
    // Local upsert through the same SDK store; +0.5 keeps later scripted
    // versions (integers) winning so the replay timeline stays authoritative.
    app.store.apply({
      type: "upsert",
      feature: {
        id: rec.id,
        feature: next,
        version: (rec.version || 0) + 0.5,
        updatedAt: app.lane === "replay" ? fmtClock(elapsedSeconds()) : rec.updatedAt,
      },
    });
    setSnippet("edit");
  }

  function renderBoard(event) {
    var records = recordList();
    renderFeed(records);
    syncIncidentMarkers(records);
    renderKpis(records);
    renderDetail();
    if (event && event.type === "upsert") checkAlerts(event, records);
  }

  /* ── alert moments (simulated client-side rule evaluation) ──────── */

  function checkAlerts(event, records) {
    var inc = event.feature && event.feature.feature;
    if (!inc) return;
    var geoKey = "geo:" + String(event.feature.id);
    if (!app.alertsFired[geoKey] && incidentInFlood(inc)) {
      app.alertsFired[geoKey] = true;
      showToast({
        kicker: "SIMULATED · GEOFENCE ALERT",
        badge: "PRO",
        badgeClass: "pro",
        tone: "critical",
        title: "Incident inside flood hazard zone",
        body:
          inc.title +
          " (" +
          inc.area +
          ") — geofence enter rule matched against " +
          (app.floodSource === "fema" ? "FEMA flood hazard polygons." : "the simulated advisory zones."),
      });
      if (!app.alertsFired["snippet:alert"]) {
        app.alertsFired["snippet:alert"] = true;
        setSnippet("alert");
      }
    }
    var threshold = app.scenario.thresholdAlert;
    if (threshold && !app.alertsFired.threshold && records.length >= threshold.count) {
      app.alertsFired.threshold = true;
      showToast({
        kicker: "SIMULATED · THRESHOLD ALERT",
        badge: "ENTERPRISE",
        badgeClass: "enterprise",
        tone: "warn",
        title: "Active incidents at or above " + threshold.count,
        body:
          "Attribute-threshold rule matched (" +
          threshold.field +
          " " +
          threshold.operator +
          " " +
          threshold.count +
          "). On a live server this fans out to email / Slack / Teams channels.",
      });
    }
  }

  /* ── units (simulated, interpolated along road paths) ───────────── */

  var UNIT_GLYPHS = { engine: "E", medic: "M", utility: "U", rescue: "R" };

  function unitPositionAt(unit, elapsed) {
    var path = unit.path;
    if (elapsed <= path[0].t) return path[0].c;
    for (var i = 1; i < path.length; i++) {
      if (elapsed <= path[i].t) {
        var a = path[i - 1];
        var b = path[i];
        var span = b.t - a.t;
        var f = span <= 0 ? 1 : (elapsed - a.t) / span;
        return [a.c[0] + (b.c[0] - a.c[0]) * f, a.c[1] + (b.c[1] - a.c[1]) * f];
      }
    }
    return path[path.length - 1].c;
  }

  function unitStatusAt(unit, elapsed) {
    var status = unit.statusTimeline[0] ? unit.statusTimeline[0].status : "available";
    for (var i = 0; i < unit.statusTimeline.length; i++) {
      if (unit.statusTimeline[i].t <= elapsed) status = unit.statusTimeline[i].status;
      else break;
    }
    return status;
  }

  function initUnits() {
    var legend = el("ps-unit-legend");
    for (var i = 0; i < app.scenario.units.length; i++) {
      var unit = app.scenario.units[i];
      var node = document.createElement("div");
      node.className = "psops-unit psops-unit-" + unit.kind;
      node.dataset.status = "available";
      node.title = unit.name + " (SIMULATED)";
      node.textContent = UNIT_GLYPHS[unit.kind] || "•";
      var marker = new window.maplibregl.Marker({ element: node }).setLngLat(unit.path[0].c).addTo(app.map);
      var row = document.createElement("li");
      row.innerHTML =
        '<span class="psops-unit-dot psops-unit-' +
        escapeHtml(unit.kind) +
        '"></span><span>' +
        escapeHtml(unit.name) +
        '</span><span class="psops-unit-status mono" id="ps-unit-status-' +
        escapeHtml(unit.id) +
        '">available</span>';
      legend.appendChild(row);
      app.unitMarkers[unit.id] = { marker: marker, el: node, unit: unit };
    }
  }

  function tickUnits() {
    var elapsed = elapsedSeconds();
    var available = 0;
    for (var i = 0; i < app.scenario.units.length; i++) {
      var unit = app.scenario.units[i];
      var entry = app.unitMarkers[unit.id];
      if (!entry) continue;
      entry.marker.setLngLat(unitPositionAt(unit, elapsed));
      var status = unitStatusAt(unit, elapsed);
      entry.el.dataset.status = status;
      entry.el.title = unit.name + " — " + status + " (SIMULATED)";
      var statusEl = el("ps-unit-status-" + unit.id);
      if (statusEl) statusEl.textContent = status;
      if (status === "available") available += 1;
    }
    if (available !== app.unitsAvailable) {
      app.unitsAvailable = available;
      el("kpi-units").textContent = String(available);
    }
    var duration = app.scenario.meta.durationSeconds;
    el("ps-clock").textContent =
      fmtClock(elapsed) +
      " / " +
      pad2(Math.floor(duration / 60)) +
      ":" +
      pad2(duration % 60) +
      " · loop " +
      app.loopCount +
      " · simulated replay";
    if (app.lane === "replay") {
      setStatus("replay", "SIMULATED replay · " + fmtClock(elapsed) + " · loop " + app.loopCount);
    } else {
      setStatus("live", "live incident stream · units remain SIMULATED");
    }
  }

  /* ── hazard layers (shared contract) + simulated zones ──────────── */

  function addZonesToMap() {
    var features = [];
    for (var i = 0; i < app.scenario.zones.length; i++) {
      var zone = app.scenario.zones[i];
      features.push({
        type: "Feature",
        geometry: { type: "Polygon", coordinates: [zone.ring] },
        properties: { id: zone.id, name: zone.name },
      });
    }
    app.map.addSource("src-sim-zones", {
      type: "geojson",
      data: { type: "FeatureCollection", features: features },
    });
    app.map.addLayer({
      id: "lyr-sim-zones-fill",
      source: "src-sim-zones",
      type: "fill",
      paint: { "fill-color": "#d9824a", "fill-opacity": 0.1 },
    });
    app.map.addLayer({
      id: "lyr-sim-zones-line",
      source: "src-sim-zones",
      type: "line",
      paint: { "line-color": "#d9824a", "line-width": 1.4, "line-dasharray": [3, 2], "line-opacity": 0.85 },
    });
    // DOM labels (no server glyphs required).
    for (var z = 0; z < app.scenario.zones.length; z++) {
      var ring = app.scenario.zones[z].ring;
      var cx = 0;
      var cy = 0;
      for (var p = 0; p < ring.length - 1; p++) {
        cx += ring[p][0];
        cy += ring[p][1];
      }
      var label = document.createElement("div");
      label.className = "psops-zone-label mono";
      label.textContent = "SIMULATED ADVISORY ZONE";
      label.title = app.scenario.zones[z].name;
      new window.maplibregl.Marker({ element: label }).setLngLat([cx / (ring.length - 1), cy / (ring.length - 1)]).addTo(app.map);
    }
  }

  function zonesAsPolygons() {
    var polys = [];
    for (var i = 0; i < app.scenario.zones.length; i++) polys.push([app.scenario.zones[i].ring]);
    return polys;
  }

  function hazardDefs() {
    var wanted = [app.config.hazardLayers.floodLayerId, app.config.hazardLayers.slrLayerId];
    var defs = [];
    for (var i = 0; i < app.layersConfig.layers.length; i++) {
      var def = app.layersConfig.layers[i];
      if (wanted.indexOf(def.id) !== -1) defs.push(def);
    }
    return defs;
  }

  function renderHazardList() {
    var list = el("ps-hazard-list");
    list.innerHTML = "";
    for (var i = 0; i < app.hazardStates.length; i++) {
      (function (state) {
        var row = document.createElement("li");
        row.className = "psops-hazard-row";
        row.dataset.available = String(state.available);
        var label = document.createElement("label");
        var checkbox = document.createElement("input");
        checkbox.type = "checkbox";
        checkbox.checked = state.visible && state.available;
        checkbox.disabled = !state.available;
        checkbox.addEventListener("change", function () {
          state.visible = checkbox.checked;
          var visibility = state.visible ? "visible" : "none";
          for (var l = 0; l < state.mapLayerIds.length; l++) {
            if (app.map.getLayer(state.mapLayerIds[l])) {
              app.map.setLayoutProperty(state.mapLayerIds[l], "visibility", visibility);
            }
          }
        });
        var name = document.createElement("span");
        name.textContent = state.def ? state.def.name : state.name;
        label.appendChild(checkbox);
        label.appendChild(name);
        if (!state.available) {
          var badge = document.createElement("span");
          badge.className = "psops-hazard-badge mono";
          badge.textContent = state.failure === "unreachable" ? "server offline" : "not yet available";
          badge.title =
            "This dataset has not been seeded on the demo server yet. The page is wired to " +
            (state.def ? state.def.service.path : "") +
            ".";
          label.appendChild(badge);
        }
        row.appendChild(label);
        list.appendChild(row);
      })(app.hazardStates[i]);
    }
    var zoneRow = document.createElement("li");
    zoneRow.className = "psops-hazard-row";
    zoneRow.dataset.available = "true";
    var zoneLabel = document.createElement("label");
    var zoneCheckbox = document.createElement("input");
    zoneCheckbox.type = "checkbox";
    zoneCheckbox.checked = true;
    zoneCheckbox.addEventListener("change", function () {
      var visibility = zoneCheckbox.checked ? "visible" : "none";
      app.map.setLayoutProperty("lyr-sim-zones-fill", "visibility", visibility);
      app.map.setLayoutProperty("lyr-sim-zones-line", "visibility", visibility);
      var labels = document.querySelectorAll(".psops-zone-label");
      for (var i = 0; i < labels.length; i++) labels[i].style.display = zoneCheckbox.checked ? "" : "none";
    });
    var zoneName = document.createElement("span");
    zoneName.textContent = "Advisory zones (simulated)";
    zoneLabel.appendChild(zoneCheckbox);
    zoneLabel.appendChild(zoneName);
    zoneRow.appendChild(zoneLabel);
    list.appendChild(zoneRow);
    var note = document.createElement("li");
    note.className = "psops-hazard-note mono";
    note.textContent =
      app.floodSource === "fema"
        ? "flood KPI uses FEMA flood hazard zones"
        : "flood KPI uses simulated advisory zones until the FEMA layer is seeded";
    list.appendChild(note);
  }

  function loadHazardLayers(client) {
    var S = window.HonuaSDK;
    var base = app.layersConfig.server.baseUrl;
    var defs = hazardDefs();
    app.hazardStates = defs.map(function (def) {
      return { def: def, available: false, probed: false, visible: true, mapLayerIds: [], failure: null };
    });

    var probes = app.hazardStates.map(function (state) {
      return client.getLayerMetadata(state.def.service.serviceId, state.def.service.layerId).then(
        function (meta) {
          state.probed = true;
          state.available = !(meta && meta.error);
          if (!state.available) state.failure = "not-seeded";
          return state;
        },
        function (error) {
          state.probed = true;
          state.available = false;
          state.failure = isNotFound(error)
            ? "not-seeded"
            : (S.isHonuaError(error) && error instanceof S.HonuaNetworkError) || error instanceof TypeError
              ? "unreachable"
              : "error";
          return state;
        }
      );
    });

    return Promise.all(probes).then(function () {
      var live = app.hazardStates.filter(function (s) {
        return s.available;
      });
      if (live.length === 0) {
        renderHazardList();
        return;
      }
      var dataset = S.createDataset({
        id: "psops-hazards",
        client: client,
        sources: live.map(function (s) {
          return {
            id: s.def.id,
            protocol: "geoservices-feature-service",
            locator: { url: base, serviceId: s.def.service.serviceId, layerId: s.def.service.layerId },
            capabilities: S.PROTOCOL_DEFAULT_CAPABILITIES["geoservices-feature-service"],
          };
        }),
        skipCompatibilityCheck: true,
      });
      var loads = live.map(function (state) {
        var def = state.def;
        app.map.addSource("src-" + def.id, {
          type: "geojson",
          data: { type: "FeatureCollection", features: [] },
          attribution: def.attribution,
        });
        app.map.addLayer(
          { id: "lyr-" + def.id, source: "src-" + def.id, type: "fill", paint: def.paint || {} },
          "lyr-sim-zones-fill"
        );
        state.mapLayerIds = ["lyr-" + def.id];
        return dataset
          .source(def.id)
          .queryAll({
            where: "1=1",
            outFields: ["*"],
            returnGeometry: true,
            outSr: 4326,
            pagination: { limit: def.maxFeatures || 4000 },
          })
          .then(function (result) {
            var src = app.map.getSource("src-" + def.id);
            if (src) src.setData(polygonFeaturesToGeoJson(result.features.slice()));
            if (def.id === app.config.hazardLayers.floodLayerId && result.features.length > 0) {
              var polys = [];
              for (var i = 0; i < result.features.length; i++) {
                var geom = result.features[i].geometry;
                if (geom && Array.isArray(geom.rings)) polys.push(geom.rings);
              }
              if (polys.length > 0) {
                app.floodPolygons = polys;
                app.floodSource = "fema";
              }
            }
          })
          .catch(function () {
            state.available = false;
            state.failure = "not-seeded";
          });
      });
      return Promise.all(loads).then(function () {
        renderHazardList();
        renderBoard(undefined);
      });
    });
  }

  /* ── basemap (graceful absence, mirrors demo.js) ────────────────── */

  function loadBasemap() {
    var bm = app.layersConfig.basemap;
    if (!bm || !bm.proxyUrl || !bm.style) return;
    fetch(bm.proxyUrl, { method: "HEAD" })
      .then(function (res) {
        if (!res.ok) return; // not yet seeded — stay on background colour
        app.map.addSource("basemap", {
          type: "vector",
          url: "pmtiles://" + bm.proxyUrl,
          attribution: bm.attribution || "",
        });
        var firstDataLayer;
        var layers = app.map.getStyle().layers || [];
        for (var i = 0; i < layers.length; i++) {
          if (layers[i].id !== "background") {
            firstDataLayer = layers[i].id;
            break;
          }
        }
        var styleLayers = bm.style.layers || [];
        for (var s = 0; s < styleLayers.length; s++) {
          try {
            var def = JSON.parse(JSON.stringify(styleLayers[s]));
            if (firstDataLayer) app.map.addLayer(def, firstDataLayer);
            else app.map.addLayer(def);
          } catch (_e) {
            /* individual basemap layer failures never break the board */
          }
        }
      })
      .catch(function () {
        /* network error — treat as absent */
      });
  }

  /* ── geocoding (live probe + GNIS fixture fallback) ─────────────── */

  function foldName(value) {
    var s = String(value).toLowerCase();
    if (s.normalize) s = s.normalize("NFD");
    var out = "";
    for (var i = 0; i < s.length; i++) {
      var code = s.charCodeAt(i);
      if (code >= 0x0300 && code <= 0x036f) continue; // strip combining marks
      if (code === 0x02bb || code === 0x2019 || code === 0x27) continue; // strip okina / apostrophes
      out += s.charAt(i);
    }
    return out;
  }

  function probeGeocoding(base, cfg) {
    if (!cfg.geocoding.enabled) {
      setGeocodeFixtureMode("geocoding: disabled");
      return;
    }
    var metaUrl = base + "/rest/services/" + encodeURIComponent(cfg.geocoding.locatorName) + "/GeocodeServer?f=json";
    fetch(metaUrl, { headers: { Accept: "application/json" } })
      .then(function (res) {
        if (res.status === 402 || res.status === 403) {
          setGeocodeFixtureMode("geocoding: requires Pro license — pending");
          return null;
        }
        if (!res.ok) {
          setGeocodeFixtureMode("geocoding: Pro locator pending");
          return null;
        }
        return res.json().then(
          function (body) {
            if (body && body.error) {
              setGeocodeFixtureMode("geocoding: Pro locator pending");
              return;
            }
            app.geocodeLane = "live";
            app.geocoder = new window.HonuaSDKOps.HonuaGeocodingClient({
              baseUrl: base,
              locatorName: cfg.geocoding.locatorName,
              // SDK gap (filed): the default fetchFn is an unbound `fetch`
              // reference, which throws "Illegal invocation" in browsers.
              fetchFn: window.fetch.bind(window),
            });
            setChip("ps-geocode-chip", "ok", "geocoding: live (Pro)");
            el("ps-geocode-note").textContent =
              "live locator: /rest/services/" + cfg.geocoding.locatorName + "/GeocodeServer";
          },
          function () {
            setGeocodeFixtureMode("geocoding: Pro locator pending");
          }
        );
      })
      .catch(function () {
        setGeocodeFixtureMode("geocoding: Pro locator pending");
      });
  }

  function setGeocodeFixtureMode(chipText) {
    app.geocodeLane = "fixture";
    app.geocoder = null;
    setChip("ps-geocode-chip", "absent", chipText);
    el("ps-geocode-note").textContent = "searching the bundled GNIS place-name fixture (replay lane)";
  }

  function fixtureSearch(text) {
    var q = foldName(text);
    var hits = [];
    for (var i = 0; i < app.places.places.length; i++) {
      var place = app.places.places[i];
      if (foldName(place.name).indexOf(q) !== -1) {
        hits.push({
          address: place.name + " · " + place.class,
          longitude: place.lng,
          latitude: place.lat,
          score: 100,
          lane: "fixture",
        });
      }
      if (hits.length >= app.config.geocoding.maxResults) break;
    }
    return hits;
  }

  function renderGeocodeResults(results, lane) {
    var list = el("ps-geocode-results");
    list.innerHTML = "";
    if (results.length === 0) {
      var empty = document.createElement("li");
      empty.className = "psops-geocode-empty mono";
      empty.textContent = "no matches" + (lane === "fixture" ? " in the GNIS fixture" : "");
      list.appendChild(empty);
      return;
    }
    for (var i = 0; i < results.length; i++) {
      (function (hit) {
        var row = document.createElement("li");
        row.className = "psops-geocode-row";
        row.innerHTML =
          "<span>" +
          escapeHtml(hit.address) +
          '</span><span class="mono psops-geocode-src">' +
          (lane === "live" ? "locator" : "GNIS fixture") +
          "</span>";
        row.addEventListener("click", function () {
          placeSearchMarker([hit.longitude, hit.latitude], hit.address);
          list.innerHTML = "";
        });
        list.appendChild(row);
      })(results[i]);
    }
  }

  function placeSearchMarker(lngLat, label) {
    if (!app.searchMarker) {
      var node = document.createElement("div");
      node.className = "psops-search-pin";
      app.searchMarker = new window.maplibregl.Marker({ element: node, anchor: "bottom" });
    }
    app.searchMarker.setLngLat(lngLat).addTo(app.map);
    app.searchMarker.getElement().title = label;
    app.map.flyTo({ center: lngLat, zoom: Math.max(app.map.getZoom(), 13), duration: 900 });
  }

  function wireGeocodeForm(base, cfg) {
    el("ps-geocode-form").addEventListener("submit", function (event) {
      event.preventDefault();
      var text = el("ps-geocode-input").value.trim();
      if (!text) return;
      setSnippet("geocode");
      if (app.geocodeLane === "live" && app.geocoder) {
        app.geocoder
          .forwardGeocode(text, {
            maxResults: cfg.geocoding.maxResults,
            spatialReferenceWkid: 4326,
            countryCodes: cfg.geocoding.countryCodes,
          })
          .then(function (candidates) {
            renderGeocodeResults(candidates, "live");
          })
          .catch(function () {
            setGeocodeFixtureMode("geocoding: live call failed — using fixture");
            renderGeocodeResults(fixtureSearch(text), "fixture");
          });
      } else {
        renderGeocodeResults(fixtureSearch(text), "fixture");
      }
    });
  }

  /* ── bootstrap ──────────────────────────────────────────────────── */

  function fetchJson(url) {
    return fetch(url).then(function (res) {
      if (!res.ok) throw new Error("failed to load " + url);
      return res.json();
    });
  }

  function bootstrap() {
    if (!window.maplibregl || !window.HonuaSDK || !window.HonuaSDKOps) {
      setStatus("error", "demo assets failed to load");
      return;
    }
    setStatus("boot", "loading scenario…");

    Promise.all([fetchJson(LAYERS_URL), fetchJson(CONFIG_URL)])
      .then(function (results) {
        app.layersConfig = results[0];
        app.config = results[1];
        return Promise.all([fetchJson(app.config.replay.scenarioUrl), fetchJson(app.config.replay.placesUrl)]);
      })
      .then(function (results) {
        app.scenario = results[0];
        app.places = results[1];
        start();
      })
      .catch(function (error) {
        setStatus("error", "demo failed to start: " + (error && error.message ? error.message : error));
      });
  }

  function start() {
    var base = app.layersConfig.server.baseUrl;
    var cfg = app.config;
    var S = window.HonuaSDK;

    SNIPPETS = buildSnippets(base, cfg, app.layersConfig);
    wireCodeStrip();
    setSnippet("realtime");

    app.floodPolygons = zonesAsPolygons();
    app.floodSource = "zones";

    app.map = new window.maplibregl.Map({
      container: "ps-map",
      style: {
        version: 8,
        glyphs: app.layersConfig.server.glyphs,
        sources: {},
        layers: [{ id: "background", type: "background", paint: { "background-color": app.layersConfig.map.background } }],
      },
      center: [-156.36, 20.815],
      zoom: 9.8,
      minZoom: 7,
      maxZoom: 17,
      attributionControl: { compact: false },
    });
    app.map.addControl(new window.maplibregl.NavigationControl({ visualizePitch: false }), "bottom-right");
    app.map.addControl(new window.maplibregl.ScaleControl({ unit: "imperial" }));

    app.map.on("load", function () {
      addZonesToMap();
      loadBasemap();

      var client = new S.HonuaClient({ baseUrl: base });
      loadHazardLayers(client);

      // Realtime store — shared by the replay and live lanes.
      app.store = window.HonuaSDKOps.createRealtimeFeatureStore();
      app.startMs = performance.now();
      app.store.subscribe(function (_state, event) {
        renderBoard(event);
      });
      app.store.connect(
        createReplayTransport(app.scenario, {
          elapsed: elapsedSeconds,
          onLoop: function () {
            app.loopCount += 1;
            app.alertsFired = {};
          },
        }),
        { sourceId: "scenario-replay", layerId: 0, requestId: "demo-public-safety-replay" }
      );

      initUnits();
      tickUnits();
      window.setInterval(tickUnits, 500);

      probeLiveLane(base, cfg);
      probeGeocoding(base, cfg);
      wireGeocodeForm(base, cfg);
      el("ps-feed").addEventListener("click", function (event) {
        var row = event.target.closest ? event.target.closest("li.psops-feed-row") : null;
        if (row && row.dataset.id) selectIncident(row.dataset.id);
      });
      el("ps-live-connect").addEventListener("click", function () {
        connectLiveLane(base, cfg);
      });

      renderBoard(undefined);
    });
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", bootstrap);
  } else {
    bootstrap();
  }
})();
